const staticData = $getWorkflowStaticData('global');

if (!staticData.usuarios) staticData.usuarios = [];
if (!staticData.donaciones) staticData.donaciones = [];
if (!staticData.notificaciones) staticData.notificaciones = [];
if (!staticData.reservas) staticData.reservas = [];

const input = $input.first().json;
const query = input.query || {};
const accion = query.accion || "inicio";

function htmlBase(contenido) {
  return `
  <!DOCTYPE html>
  <html lang="es">
  <head>
    <meta charset="UTF-8">
    <title>Plataforma de Excedentes Alimentarios</title>
    <style>
      body { font-family: Arial, sans-serif; background: #f4f7f5; margin: 0; padding: 0; }
      header { background: #2e7d32; color: white; padding: 25px; text-align: center; }
      main { width: 90%; max-width: 950px; margin: 30px auto; background: white; padding: 25px; border-radius: 12px; box-shadow: 0 2px 12px rgba(0,0,0,0.12); }
      nav a { display: inline-block; margin: 6px; padding: 9px 13px; background: #e8f5e9; color: #2e7d32; text-decoration: none; border-radius: 6px; font-weight: bold; }
      nav a:hover { background: #c8e6c9; }
      nav a.alerta { background: #ffebee; color: #c62828; }
      nav a.alerta:hover { background: #ffcdd2; }
      input, select, textarea, button { width: 100%; padding: 10px; margin: 8px 0 14px 0; border-radius: 6px; border: 1px solid #ccc; box-sizing: border-box; }
      button { background: #2e7d32; color: white; border: none; cursor: pointer; font-weight: bold; }
      button:hover { background: #256628; }
      button.btn-rojo { background: #c62828; }
      button.btn-rojo:hover { background: #b71c1c; }
      .card { border: 1px solid #ddd; border-left: 6px solid #2e7d32; padding: 15px; margin: 15px 0; border-radius: 8px; background: #fafafa; }
      .critica { border-left-color: #d32f2f; background: #fff3f3; }
      .vencida { border-left-color: #7b1fa2; background: #f3e5f5; }
      .badge { display: inline-block; background: #d32f2f; color: white; padding: 4px 8px; border-radius: 5px; font-size: 12px; margin-right: 6px; }
      .badge-vencido { background: #7b1fa2; }
      .frio { background: #0277bd; }
      .ok { background: #e8f5e9; border-left: 6px solid #2e7d32; padding: 12px; border-radius: 8px; }
      .error { background: #ffebee; border-left: 6px solid #d32f2f; padding: 12px; border-radius: 8px; }
      .advertencia { background: #fff3e0; border-left: 6px solid #e65100; padding: 12px; border-radius: 8px; margin-bottom: 16px; }
      table { width: 100%; border-collapse: collapse; margin-top: 15px; }
      th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }
      th { background: #e8f5e9; }
    </style>
  </head>
  <body>
    <header>
      <h1>Plataforma de Gestión de Excedentes Alimentarios</h1>
      <p>Prototipo funcional en n8n + Docker</p>
    </header>
    <main>
      <nav>
        <a href="?accion=inicio">Inicio</a>
        <a href="?accion=registro">Registrar usuario</a>
        <a href="?accion=usuarios">Usuarios</a>
        <a href="?accion=publicar">Publicar excedente</a>
        <a href="?accion=publicar_vencido" class="alerta">⚠️ Reportar producto vencido</a>
        <a href="?accion=donaciones">Ver donaciones</a>
        <a href="?accion=notificaciones">Notificaciones ONG</a>
        <a href="?accion=reservas">Reservas</a>
      </nav>
      <hr>
      ${contenido}
    </main>
  </body>
  </html>
  `;
}

function responder(contenido) {
  return [{ json: { html: htmlBase(contenido), accionPendiente: null } }];
}

function responderConAccion(contenido, accion, payload) {
  return [{ json: { html: htmlBase(contenido), accionPendiente: accion, payload } }];
}

function escapar(texto) {
  if (!texto) return "";
  return String(texto)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;");
}

if (accion === "inicio") {
  return responder(`
    <h2>Bienvenido al sistema</h2>
    <p>Este prototipo representa el flujo principal del Sprint 1 usando n8n como backend mediante Webhooks.</p>
    <h3>Funcionalidades implementadas</h3>
    <ul>
      <li>Registro de usuarios Donante y Organización Social.</li>
      <li>Publicación de excedentes alimentarios.</li>
      <li>Validación de fecha de vencimiento.</li>
      <li>Marcado de productos con cadena de frío.</li>
      <li>Priorización por vencimiento más próximo.</li>
      <li>Generación de alertas para organizaciones sociales.</li>
      <li>Reserva de donaciones.</li>
      <li>Generación de QR simulado para retiro.</li>
      <li><strong>Reporte de productos vencidos con alerta push a ONGs.</strong></li>
    </ul>
    <p class="ok"><strong>Estado:</strong> n8n funcionando correctamente con Docker.</p>
  `);
}

if (accion === "registro") {
  return responder(`
    <h2>Registrar usuario</h2>
    <form method="GET">
      <input type="hidden" name="accion" value="guardar_usuario">
      <label>Nombre:</label>
      <input name="nombre" required>
      <label>Email:</label>
      <input name="email" type="email" required>
      <label>Rol:</label>
      <select name="rol" required>
        <option value="DONANTE">Donante</option>
        <option value="ONG">Organización Social</option>
      </select>
      <label>Dirección:</label>
      <input name="direccion" required>
      <button type="submit">Guardar usuario</button>
    </form>
  `);
}

if (accion === "guardar_usuario") {
  const usuario = {
    id: Date.now(),
    nombre: escapar(query.nombre),
    email: escapar(query.email),
    rol: query.rol,
    direccion: escapar(query.direccion),
    verificado: true,
    creadoEn: new Date().toISOString()
  };
  staticData.usuarios.push(usuario);
  return responder(`
    <h2>Usuario registrado correctamente</h2>
    <div class="ok">
      <p><strong>ID:</strong> ${usuario.id}</p>
      <p><strong>Nombre:</strong> ${usuario.nombre}</p>
      <p><strong>Email:</strong> ${usuario.email}</p>
      <p><strong>Rol:</strong> ${usuario.rol}</p>
      <p><strong>Dirección:</strong> ${usuario.direccion}</p>
    </div>
    <p>Este usuario ya puede participar en el flujo del sistema.</p>
    <a href="?accion=usuarios">Ver usuarios registrados</a>
  `);
}

if (accion === "usuarios") {
  const filas = staticData.usuarios.map(u => `
    <tr>
      <td>${u.id}</td>
      <td>${u.nombre}</td>
      <td>${u.email}</td>
      <td>${u.rol}</td>
      <td>${u.direccion}</td>
    </tr>
  `).join("");
  return responder(`
    <h2>Usuarios registrados</h2>
    <table>
      <tr><th>ID</th><th>Nombre</th><th>Email</th><th>Rol</th><th>Dirección</th></tr>
      ${filas || `<tr><td colspan="5">No hay usuarios registrados.</td></tr>`}
    </table>
  `);
}

if (accion === "publicar") {
  const donantes = staticData.usuarios.filter(u => u.rol === "DONANTE");
  if (donantes.length === 0) {
    return responder(`
      <h2>Publicar excedente</h2>
      <p class="error">Primero debes registrar al menos un usuario con rol Donante.</p>
      <a href="?accion=registro">Registrar usuario</a>
    `);
  }
  const opcionesDonantes = donantes.map(u => `<option value="${u.id}">${u.nombre}</option>`).join("");
  return responder(`
    <h2>Publicar excedente alimentario</h2>
    <form method="GET">
      <input type="hidden" name="accion" value="guardar_donacion">
      <label>Donante:</label>
      <select name="donanteId" required>${opcionesDonantes}</select>
      <label>Nombre del producto:</label>
      <input name="nombre" placeholder="Ej: Panadería del día" required>
      <label>Categoría:</label>
      <select name="categoria" required>
        <option value="Panadería">Panadería</option>
        <option value="Lácteos">Lácteos</option>
        <option value="Frutas y verduras">Frutas y verduras</option>
        <option value="Abarrotes">Abarrotes</option>
        <option value="Otros">Otros</option>
      </select>
      <label>Cantidad:</label>
      <input name="cantidad" placeholder="Ej: 15" type="number" required>
      <label>Fecha y hora de vencimiento:</label>
      <input name="vencimiento" type="datetime-local" required>
      <label>Cadena de frío:</label>
      <select name="cadenaFrio">
        <option value="NO">No requiere</option>
        <option value="SI">Sí requiere</option>
      </select>
      <label>Observaciones:</label>
      <textarea name="observaciones" placeholder="Ej: Producto apto para consumo, retirar hoy."></textarea>
      <button type="submit">Publicar donación</button>
    </form>
  `);
}

// ─── NUEVA ACCIÓN: formulario producto vencido ────────────────────────────────
if (accion === "publicar_vencido") {
  const donantes = staticData.usuarios.filter(u => u.rol === "DONANTE");
  if (donantes.length === 0) {
    return responder(`
      <h2>Reportar producto vencido</h2>
      <p class="error">Primero debes registrar al menos un usuario con rol Donante.</p>
      <a href="?accion=registro">Registrar usuario</a>
    `);
  }
  const opcionesDonantes = donantes.map(u => `<option value="${u.id}">${u.nombre}</option>`).join("");
  return responder(`
    <h2>⚠️ Reportar producto vencido</h2>
    <div class="advertencia">
      <strong>Atención:</strong> Este formulario es para registrar productos cuya fecha de vencimiento ya expiró.
      Al registrarlo, las organizaciones sociales recibirán una alerta de producto vencido por notificación push.
    </div>
    <form method="GET">
      <input type="hidden" name="accion" value="guardar_vencido">
      <label>Donante:</label>
      <select name="donanteId" required>${opcionesDonantes}</select>
      <label>Nombre del producto:</label>
      <input name="nombre" placeholder="Ej: Yogur natural" required>
      <label>Categoría:</label>
      <select name="categoria" required>
        <option value="Panadería">Panadería</option>
        <option value="Lácteos">Lácteos</option>
        <option value="Frutas y verduras">Frutas y verduras</option>
        <option value="Abarrotes">Abarrotes</option>
        <option value="Otros">Otros</option>
      </select>
      <label>Cantidad:</label>
      <input name="cantidad" placeholder="Ej: 10" type="number" required>
      <label>Fecha de vencimiento (ya expirada):</label>
      <input name="vencimiento" type="datetime-local" required>
      <label>Observaciones:</label>
      <textarea name="observaciones" placeholder="Ej: Vencido ayer, revisar si aún es apto para uso no alimentario."></textarea>
      <button type="submit" class="btn-rojo">⚠️ Registrar producto vencido</button>
    </form>
  `);
}

// ─── NUEVA ACCIÓN: guardar producto vencido ───────────────────────────────────
if (accion === "guardar_vencido") {
  const vencimiento = new Date(query.vencimiento);
  const ahora = new Date();

  if (vencimiento >= ahora) {
    return responder(`
      <h2>Error al reportar</h2>
      <p class="error">La fecha ingresada aún no ha vencido. Para productos con fecha futura usa <a href="?accion=publicar">Publicar excedente</a>.</p>
      <a href="?accion=publicar_vencido">Volver al formulario</a>
    `);
  }

  const donante = staticData.usuarios.find(u => String(u.id) === String(query.donanteId));

  const donacion = {
    id: Date.now(),
    donanteId: query.donanteId,
    donanteNombre: donante ? donante.nombre : "Donante no identificado",
    nombre: escapar(query.nombre),
    categoria: escapar(query.categoria),
    cantidad: Number(query.cantidad),
    vencimiento: query.vencimiento,
    cadenaFrio: false,
    observaciones: escapar(query.observaciones || ""),
    estado: "VENCIDO",
    creadoEn: new Date().toISOString()
  };

  staticData.donaciones.push(donacion);

  // Generar notificaciones internas de alerta para todas las ONGs
  const organizaciones = staticData.usuarios.filter(u => u.rol === "ONG");
  organizaciones.forEach(org => {
    staticData.notificaciones.push({
      id: Date.now() + Math.random(),
      usuarioId: org.id,
      organizacionNombre: org.nombre,
      donacionId: donacion.id,
      mensaje: `⚠️ ALERTA PRODUCTO VENCIDO: ${donacion.nombre} (${donacion.cantidad} unidades). Vencido el ${donacion.vencimiento}. Donante: ${donacion.donanteNombre}.`,
      fecha: new Date().toISOString(),
      leida: false,
      esAlertaVencido: true
    });
  });

  return responderConAccion(`
    <h2>Producto vencido registrado</h2>
    <div class="critica">
      <p><strong>Producto:</strong> ${donacion.nombre}</p>
      <p><strong>Donante:</strong> ${donacion.donanteNombre}</p>
      <p><strong>Categoría:</strong> ${donacion.categoria}</p>
      <p><strong>Cantidad:</strong> ${donacion.cantidad}</p>
      <p><strong>Fecha vencimiento:</strong> ${donacion.vencimiento}</p>
      <p><strong>Estado:</strong> <span class="badge badge-vencido">VENCIDO</span></p>
    </div>
    <p>Se generaron alertas de producto vencido para ${organizaciones.length} organización(es) social(es).</p>
    <p class="advertencia">⚠️ Notificación push de alerta enviada a ONGs por ntfy.</p>
    <a href="?accion=notificaciones">Ver notificaciones ONG</a>
  `, "guardar_vencido", {
    nombre_producto: donacion.nombre,
    categoria: donacion.categoria,
    cantidad: donacion.cantidad,
    fecha_vencimiento: donacion.vencimiento
  });
}

if (accion === "guardar_donacion") {
  const vencimiento = new Date(query.vencimiento);
  const ahora = new Date();

  const donante = staticData.usuarios.find(u => String(u.id) === String(query.donanteId));

  const donacion = {
    id: Date.now(),
    donanteId: query.donanteId,
    donanteNombre: donante ? donante.nombre : "Donante no identificado",
    nombre: escapar(query.nombre),
    categoria: escapar(query.categoria),
    cantidad: Number(query.cantidad),
    vencimiento: query.vencimiento,
    cadenaFrio: query.cadenaFrio === "SI",
    observaciones: escapar(query.observaciones || ""),
    estado: "DISPONIBLE",
    creadoEn: new Date().toISOString()
  };

  staticData.donaciones.push(donacion);

  const organizaciones = staticData.usuarios.filter(u => u.rol === "ONG");
  organizaciones.forEach(org => {
    staticData.notificaciones.push({
      id: Date.now() + Math.random(),
      usuarioId: org.id,
      organizacionNombre: org.nombre,
      donacionId: donacion.id,
      mensaje: `Nueva donación disponible: ${donacion.nombre} - ${donacion.cantidad}`,
      fecha: new Date().toISOString(),
      leida: false
    });
  });

  return responderConAccion(`
    <h2>Donación publicada correctamente</h2>
    <div class="ok">
      <p><strong>Producto:</strong> ${donacion.nombre}</p>
      <p><strong>Donante:</strong> ${donacion.donanteNombre}</p>
      <p><strong>Categoría:</strong> ${donacion.categoria}</p>
      <p><strong>Cantidad:</strong> ${donacion.cantidad}</p>
      <p><strong>Vencimiento:</strong> ${donacion.vencimiento}</p>
      <p><strong>Cadena de frío:</strong> ${donacion.cadenaFrio ? "Sí requiere" : "No requiere"}</p>
    </div>
    <p>Se generaron alertas para ${organizaciones.length} organización(es) social(es).</p>
    <p class="ok">✅ Notificación push enviada a ONG.</p>
    <a href="?accion=donaciones">Ver donaciones</a>
  `, "guardar_donacion", {
    nombre_producto: donacion.nombre,
    categoria: donacion.categoria,
    cantidad: donacion.cantidad,
    fecha_vencimiento: donacion.vencimiento
  });
}

if (accion === "donaciones") {
  const disponibles = staticData.donaciones
    .filter(d => d.estado === "DISPONIBLE")
    .sort((a, b) => new Date(a.vencimiento) - new Date(b.vencimiento));

  const organizaciones = staticData.usuarios.filter(u => u.rol === "ONG");
  const opcionesONG = organizaciones.map(u => `<option value="${u.id}">${u.nombre}</option>`).join("");

  const lista = disponibles.map(d => {
    const horasRestantes = (new Date(d.vencimiento) - new Date()) / 1000 / 60 / 60;
    const critica = horasRestantes <= 6;
    return `
      <div class="card ${critica ? "critica" : ""}">
        <h3>${d.nombre}</h3>
        ${critica ? `<span class="badge">Urgente</span>` : ""}
        ${d.cadenaFrio ? `<span class="badge frio">Cadena de frío</span>` : ""}
        <p><strong>Donante:</strong> ${d.donanteNombre}</p>
        <p><strong>Categoría:</strong> ${d.categoria}</p>
        <p><strong>Cantidad:</strong> ${d.cantidad}</p>
        <p><strong>Vencimiento:</strong> ${d.vencimiento}</p>
        <p><strong>Estado:</strong> ${d.estado}</p>
        <p><strong>Observaciones:</strong> ${d.observaciones || "Sin observaciones"}</p>
        ${
          organizaciones.length > 0
          ? `<form method="GET">
              <input type="hidden" name="accion" value="reservar">
              <input type="hidden" name="donacionId" value="${d.id}">
              <label>Organización que reserva:</label>
              <select name="usuarioId" required>${opcionesONG}</select>
              <button type="submit">Reservar donación</button>
            </form>`
          : `<p class="error">No hay organizaciones sociales registradas para reservar.</p>`
        }
      </div>
    `;
  }).join("");

  return responder(`
    <h2>Donaciones disponibles</h2>
    <p>Las donaciones se muestran ordenadas por fecha de vencimiento más próxima.</p>
    ${lista || "<p>No hay donaciones disponibles.</p>"}
  `);
}

if (accion === "reservar") {
  const donacion = staticData.donaciones.find(d => String(d.id) === String(query.donacionId));
  const organizacion = staticData.usuarios.find(u => String(u.id) === String(query.usuarioId));

  if (!donacion || donacion.estado !== "DISPONIBLE") {
    return responder(`
      <h2>No se pudo reservar</h2>
      <p class="error">La donación ya no está disponible.</p>
      <a href="?accion=donaciones">Volver a donaciones</a>
    `);
  }

  if (!organizacion || organizacion.rol !== "ONG") {
    return responder(`
      <h2>No se pudo reservar</h2>
      <p class="error">Solo una organización social puede reservar donaciones.</p>
      <a href="?accion=donaciones">Volver a donaciones</a>
    `);
  }

  donacion.estado = "RESERVADA";

  const reserva = {
    id: Date.now(),
    donacionId: donacion.id,
    producto: donacion.nombre,
    usuarioId: organizacion.id,
    organizacionNombre: organizacion.nombre,
    codigoQR: `QR-${donacion.id}-${organizacion.id}`,
    fechaReserva: new Date().toISOString(),
    estado: "ACTIVA"
  };

  staticData.reservas.push(reserva);

  return responder(`
    <h2>Donación reservada correctamente</h2>
    <div class="ok">
      <p><strong>Producto:</strong> ${donacion.nombre}</p>
      <p><strong>Reservada por:</strong> ${organizacion.nombre}</p>
      <p><strong>Estado:</strong> RESERVADA</p>
      <p><strong>Código QR simulado:</strong></p>
      <h3>${reserva.codigoQR}</h3>
    </div>
    <p>Este QR simula la validación de retiro de la donación.</p>
    <a href="?accion=reservas">Ver reservas</a>
  `);
}

if (accion === "notificaciones") {
  const organizaciones = staticData.usuarios.filter(u => u.rol === "ONG");
  if (organizaciones.length === 0) {
    return responder(`
      <h2>Notificaciones ONG</h2>
      <p class="error">No hay organizaciones sociales registradas.</p>
      <a href="?accion=registro">Registrar organización</a>
    `);
  }
  const opcionesONG = organizaciones.map(u => `<option value="${u.id}">${u.nombre}</option>`).join("");
  if (!query.usuarioId) {
    return responder(`
      <h2>Consultar notificaciones</h2>
      <form method="GET">
        <input type="hidden" name="accion" value="notificaciones">
        <label>Organización Social:</label>
        <select name="usuarioId" required>${opcionesONG}</select>
        <button type="submit">Ver notificaciones</button>
      </form>
    `);
  }
  const notificaciones = staticData.notificaciones.filter(n => String(n.usuarioId) === String(query.usuarioId));
  const lista = notificaciones.map(n => `
    <div class="card ${n.esAlertaVencido ? 'vencida' : ''}">
      ${n.esAlertaVencido ? '<span class="badge badge-vencido">⚠️ PRODUCTO VENCIDO</span>' : ''}
      <p>${n.mensaje}</p>
      <p><strong>Fecha:</strong> ${n.fecha}</p>
    </div>
  `).join("");
  return responder(`
    <h2>Notificaciones de la organización</h2>
    ${lista || "<p>No hay notificaciones registradas.</p>"}
  `);
}

if (accion === "reservas") {
  const lista = staticData.reservas.map(r => `
    <div class="card">
      <h3>${r.producto}</h3>
      <p><strong>Organización:</strong> ${r.organizacionNombre}</p>
      <p><strong>Fecha reserva:</strong> ${r.fechaReserva}</p>
      <p><strong>Estado:</strong> ${r.estado}</p>
      <p><strong>QR:</strong> ${r.codigoQR}</p>
    </div>
  `).join("");
  return responder(`
    <h2>Reservas registradas</h2>
    ${lista || "<p>No hay reservas registradas.</p>"}
  `);
}

return responder(`
  <h2>Acción no reconocida</h2>
  <p>La acción solicitada no existe.</p>
`);
